1	// Smoke test for the deployed metrics-refresh edge function (US-021).
2	//
3	// Usage: bun run scripts/test/metrics-refresh.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks role + validation + 404 assertions; SUPABASE_SERVICE_ROLE_KEY
6	// unlocks the 429 throttle + 422 unlinked assertions (they need to mutate
7	// the seed social_link). Missing either secret SKIPs the corresponding
8	// assertions with a printed notice rather than failing — the full 10-case
9	// matrix runs in CI where every env var is configured.
10	//
11	// All branches exercised here short-circuit BEFORE the Apify dispatch, so
12	// the test does not burn Apify credits. The happy-path (200 + queued run)
13	// is verified live during mobile-mcp UI verification, not here.
14	//
15	// Asserts:
16	//   1. Missing Authorization → 401 UNAUTHORIZED                                          [always]
17	//   2. Non-Bearer token → 401 UNAUTHORIZED                                               [always]
18	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                                   [always]
19	//   4. Lister-role JWT → 403 FORBIDDEN                                                   [jwtSecret]
20	//   5. Creator JWT + malformed JSON body → 400 INVALID_JSON                              [jwtSecret]
21	//   6. Creator JWT + missing social_link_id → 400 INVALID_REQUEST                        [jwtSecret]
22	//   7. Creator JWT + non-UUID social_link_id → 400 INVALID_REQUEST                       [jwtSecret]
23	//   8. Creator JWT + UUID not owned by caller → 404 LINK_NOT_FOUND                       [jwtSecret]
24	//   9. Owner JWT + recently-bumped link → 429 RATE_LIMIT with retry_after_sec            [jwtSecret + serviceRole]
25	//  10. Owner JWT + link with status='unlinked' → 422 LINK_UNLINKED                       [jwtSecret + serviceRole]
26	//  11. Owner JWT + latest fresh snapshot within window → 200 already_fresh               [jwtSecret + serviceRole]
27	
28	const supabaseUrl = process.env.SUPABASE_URL;
29	const anonKey = process.env.SUPABASE_ANON_KEY;
30	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
31	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
32	if (!supabaseUrl || !anonKey) {
33	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
34	  process.exit(1);
35	}
36	if (!jwtSecret) {
37	  console.log(
38	    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–10 (role/validation/404/429/422)",
39	  );
40	}
41	if (!serviceRoleKey) {
42	  console.log(
43	    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertions 9–10 (throttle/unlinked)",
44	  );
45	}
46	
47	const endpoint = `${supabaseUrl}/functions/v1/metrics-refresh`;
48	
49	// Seeded fixtures from scripts/sql/seed.sql (used by the apify-webhook smoke
50	// test as well). The test mutates last_scrape_attempt_at and status on
51	// these rows and restores them in a finally block.
52	const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
53	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
54	
55	const encoder = new TextEncoder();
56	
57	function b64url(bytes: Uint8Array): string {
58	  let s = "";
59	  for (const b of bytes) s += String.fromCharCode(b);
60	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
61	}
62	
63	async function signMarketifyJwt(
64	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
65	  secret: string,
66	): Promise<string> {
67	  const now = Math.floor(Date.now() / 1000);
68	  const payload = { ...claims, iat: now, exp: now + 300 };
69	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
70	  const body = b64url(encoder.encode(JSON.stringify(payload)));
71	  const signingInput = `${header}.${body}`;
72	  const key = await crypto.subtle.importKey(
73	    "raw",
74	    encoder.encode(secret),
75	    { name: "HMAC", hash: "SHA-256" },
76	    false,
77	    ["sign"],
78	  );
79	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
80	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
81	}
82	
83	async function post(
84	  bodyValue: string | Record<string, unknown> | null,
85	  authHeader: string | null,
86	) {
87	  const headers: Record<string, string> = {
88	    "Content-Type": "application/json",
89	    apikey: anonKey!,
90	  };
91	  if (authHeader) headers["Authorization"] = authHeader;
92	  const res = await fetch(endpoint, {
93	    method: "POST",
94	    headers,
95	    body: bodyValue == null
96	      ? undefined
97	      : typeof bodyValue === "string"
98	      ? bodyValue
99	      : JSON.stringify(bodyValue),
100	  });
101	  const data = await res.json().catch(() => null);
102	  return { status: res.status, data };
103	}
104	
105	function expect(label: string, cond: boolean, ctx: unknown) {
106	  if (!cond) {
107	    console.error(`FAIL ${label}:`, ctx);
108	    process.exit(1);
109	  }
110	  console.log(`ok — ${label}`);
111	}
112	
113	type SocialLinkStatus = "linked" | "unlinked" | "failed_fetch";
114	
115	async function setLinkFields(
116	  linkId: string,
117	  fields: {
118	    last_scrape_attempt_at?: string | null;
119	    status?: SocialLinkStatus;
120	  },
121	): Promise<void> {
122	  const res = await fetch(
123	    `${supabaseUrl}/rest/v1/social_links?id=eq.${linkId}`,
124	    {
125	      method: "PATCH",
126	      headers: {
127	        apikey: serviceRoleKey!,
128	        Authorization: `Bearer ${serviceRoleKey}`,
129	        "Content-Type": "application/json",
130	        Prefer: "return=minimal",
131	      },
132	      body: JSON.stringify(fields),
133	    },
134	  );
135	  if (!res.ok) {
136	    throw new Error(
137	      `setLinkFields failed: ${res.status} ${await res.text()}`,
138	    );
139	  }
140	}
141	
142	// Snapshot the seed link's current state so we can restore it later.
143	// Only needed when the service role is available (tests 9 and 10 mutate
144	// the link). Without the service role we skip those tests and the
145	// snapshot + restore are no-ops.
146	type LinkSnapshot = {
147	  status: SocialLinkStatus;
148	  last_scrape_attempt_at: string | null;
149	};
150	let snapshot: LinkSnapshot | null = null;
151	if (serviceRoleKey) {
152	  const snapshotRes = await fetch(
153	    `${supabaseUrl}/rest/v1/social_links?id=eq.${SEED_TIKTOK_SOCIAL_LINK_ID}&select=status,last_scrape_attempt_at`,
154	    {
155	      headers: {
156	        apikey: serviceRoleKey,
157	        Authorization: `Bearer ${serviceRoleKey}`,
158	      },
159	    },
160	  );
161	  if (!snapshotRes.ok) {
162	    console.error("seed link snapshot failed:", await snapshotRes.text());
163	    process.exit(1);
164	  }
165	  const [row] = (await snapshotRes.json()) as LinkSnapshot[];
166	  if (!row) {
167	    console.error(
168	      "seed social_link missing — run scripts/sql/seed.sql before this test",
169	    );
170	    process.exit(1);
171	  }
172	  snapshot = row;
173	}
174	
175	// Tracks metric_snapshot rows inserted by test 11 so restore() can remove
176	// them from the seed DB. Populated only when the service role is available.
177	const insertedSnapshotIds: string[] = [];
178	
179	let restored = false;
180	async function restore() {
181	  if (restored || !serviceRoleKey) return;
182	  restored = true;
183	  if (snapshot) {
184	    await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, {
185	      status: snapshot.status,
186	      last_scrape_attempt_at: snapshot.last_scrape_attempt_at,
187	    });
188	  }
189	  if (insertedSnapshotIds.length > 0) {
190	    const idList = insertedSnapshotIds.map((id) => `"${id}"`).join(",");
191	    const res = await fetch(
192	      `${supabaseUrl}/rest/v1/metric_snapshots?id=in.(${idList})`,
193	      {
194	        method: "DELETE",
195	        headers: {
196	          apikey: serviceRoleKey,
197	          Authorization: `Bearer ${serviceRoleKey}`,
198	          Prefer: "return=minimal",
199	        },
200	      },
201	    );
202	    if (!res.ok) {
203	      console.error(
204	        "cleanup of inserted metric_snapshots failed:",
205	        res.status,
206	        await res.text(),
207	      );
208	    }
209	  }
210	}
211	
212	try {
213	  // 1. No Authorization header
214	  {
215	    const r = await post({ social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID }, null);
216	    expect(
217	      "missing auth → 401 UNAUTHORIZED",
218	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
219	      r,
220	    );
221	  }
222	
223	  // 2. Non-Bearer scheme
224	  {
225	    const r = await post(
226	      { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
227	      "Basic abcdef",
228	    );
229	    expect(
230	      "non-bearer → 401 UNAUTHORIZED",
231	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
232	      r,
233	    );
234	  }
235	
236	  // 3. JWT signed with wrong secret
