export default function CreatorProfile() {
  const { user, signOut } = useAuth();
  const { show: showToast } = useToast();

  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
  const [links, setLinks] = useState<SocialLink[]>([]);
