// One-off probe (not committed) — verify whether the Supabase project's
// JWT secret matches MARKETIFY_JWT_SECRET by: (1) signing up a real
// creator via auth-signup-creator, (2) hitting PostgREST with the returned
// JWT. If PostgREST returns 200 with the row, the secrets are aligned.
// If 401/PGRST301, the drift that blocks US-036 verification persists.

const supabaseUrl = process.env.SUPABASE_URL!;
const anonKey = process.env.SUPABASE_ANON_KEY!;
if (!supabaseUrl || !anonKey) {
  console.error("Missing SUPABASE_URL or SUPABASE_ANON_KEY");
  process.exit(1);
}

const unique = Date.now();
const signupBody = {
  username: `us036probe_${unique}`,
  tiktok_handle: `us036probe_tt_${unique}`,
  instagram_handle: `us036probe_ig_${unique}`,
};

const signupRes = await fetch(
  `${supabaseUrl}/functions/v1/auth-signup-creator`,
  {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${anonKey}`,
      apikey: anonKey,
    },
    body: JSON.stringify(signupBody),
  },
);
const signupData = await signupRes.json();
console.log("signup status:", signupRes.status);
console.log("signup role:", signupData?.role);
console.log("signup user_id:", signupData?.user_id);
const token = signupData?.token;
if (!token) {
  console.error("No token; aborting.");
  process.exit(1);
}

const probeRes = await fetch(
  `${supabaseUrl}/rest/v1/creator_profiles?select=user_id,tiktok_follower_count&user_id=eq.${signupData.user_id}`,
  {
    headers: {
      apikey: anonKey,
      Authorization: `Bearer ${token}`,
    },
  },
);
const probeText = await probeRes.text();
console.log("---");
console.log("PostgREST status:", probeRes.status);
console.log("PostgREST body:", probeText);

