// Smoke test for the deployed get-listing-detail edge function (US-039).
//
// Usage: bun run scripts/test/get-listing-detail.ts
// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
// unlocks JWT-authed tests; SUPABASE_SERVICE_ROLE_KEY unlocks the
// ineligibility case (needs to mutate creator_profiles.tiktok_follower_count
// below threshold + restore it). Missing either secret SKIPs the
// corresponding assertions with a printed notice rather than failing.
//
// Asserts:
//   1. Missing Authorization → 401 UNAUTHORIZED                               [always]
//   2. Non-Bearer token → 401 UNAUTHORIZED                                    [always]
//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                        [always]
//   4. Lister-role JWT → 403 FORBIDDEN                                        [jwtSecret]
//   5. Malformed JSON body → 400 INVALID_JSON                                 [jwtSecret]
//   6. Missing listing_id → 400 INVALID_REQUEST                               [jwtSecret]
//   7. Non-UUID listing_id → 400 INVALID_REQUEST                              [jwtSecret]
//   8. Unknown listing_id → 404 LISTING_NOT_FOUND                             [jwtSecret]
//   9. Seed creator + seed listing (1k/500 thresholds, creator has 93.7M/15k)
//      → 200 with eligible:true, pre/post conditions split, sample_videos,
//        has_active_application:false                                         [jwtSecret]
//  10. Same call after mutating creator_profiles.tiktok_follower_count to 500
//      → 200 with eligible:false AND failed_conditions including tiktok
//        min_followers with required=1000, actual=500                         [jwtSecret + serviceRole]

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
if (!supabaseUrl || !anonKey) {
  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
  process.exit(1);
}
if (!jwtSecret) {
  console.log(
    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–10",
  );
}
if (!serviceRoleKey) {
  console.log(
    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertion 10 (ineligible)",
  );
}

const endpoint = `${supabaseUrl}/functions/v1/get-listing-detail`;

// Seed fixtures — same UUIDs used by other smoke tests.
const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
const SEED_LISTING_ID = "11111111-1111-1111-1111-111111111010";

const encoder = new TextEncoder();

function b64url(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

async function signMarketifyJwt(
  claims: { sub: string; role: "creator" | "lister"; session_id: string },
  secret: string,
): Promise<string> {
  const now = Math.floor(Date.now() / 1000);
  const payload = { ...claims, iat: now, exp: now + 300 };
  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
  const body = b64url(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${header}.${body}`;
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
}

async function post(
  bodyValue: string | Record<string, unknown> | null,
  authHeader: string | null,
) {
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    apikey: anonKey!,
  };
  if (authHeader) headers["Authorization"] = authHeader;
  const res = await fetch(endpoint, {
    method: "POST",
    headers,
    body: bodyValue == null
      ? undefined
      : typeof bodyValue === "string"
      ? bodyValue
      : JSON.stringify(bodyValue),
  });
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

function expect(label: string, cond: boolean, ctx: unknown) {
  if (!cond) {
    console.error(`FAIL ${label}:`, JSON.stringify(ctx, null, 2));
    process.exit(1);
  }
  console.log(`ok — ${label}`);
}

async function setCreatorMetric(
  column: "tiktok_follower_count",
  value: number | null,
): Promise<void> {
  const res = await fetch(
    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}`,
    {
      method: "PATCH",
      headers: {
        apikey: serviceRoleKey!,
        Authorization: `Bearer ${serviceRoleKey}`,
        "Content-Type": "application/json",
        Prefer: "return=minimal",
      },
      body: JSON.stringify({ [column]: value }),
    },
  );
  if (!res.ok) {
    throw new Error(`setCreatorMetric failed: ${res.status} ${await res.text()}`);
  }
}

// Snapshot the seed creator's tiktok_follower_count so we can restore it
// after the ineligibility case. Only fetched when we have service role.
let originalTiktokFollowerCount: number | null = null;
if (serviceRoleKey) {
  const snapRes = await fetch(
    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}&select=tiktok_follower_count`,
    {
      headers: {
        apikey: serviceRoleKey,
        Authorization: `Bearer ${serviceRoleKey}`,
      },
    },
  );
  if (!snapRes.ok) {
    console.error("creator_profiles snapshot failed:", await snapRes.text());
    process.exit(1);
  }
  const rows = (await snapRes.json()) as Array<{ tiktok_follower_count: number | null }>;
  if (rows.length === 0) {
    console.error(
      "seed creator_profiles missing — run seed fixtures before this test",
    );
    process.exit(1);
  }
  originalTiktokFollowerCount = rows[0].tiktok_follower_count;
}

let restored = false;
async function restore() {
  if (restored || !serviceRoleKey) return;
  restored = true;
  await setCreatorMetric("tiktok_follower_count", originalTiktokFollowerCount);
}

try {
  // 1. No Authorization header
  {
    const r = await post({ listing_id: SEED_LISTING_ID }, null);
    expect(
      "missing auth → 401 UNAUTHORIZED",
      r.status === 401 && r.data?.error === "UNAUTHORIZED",
      r,
    );
  }

  // 2. Non-Bearer scheme
  {
    const r = await post({ listing_id: SEED_LISTING_ID }, "Basic abcdef");
    expect(
      "non-bearer → 401 UNAUTHORIZED",
      r.status === 401 && r.data?.error === "UNAUTHORIZED",
      r,
    );
  }

  // 3. JWT signed with wrong secret
  {
    const badJwt = await signMarketifyJwt(
      {
        sub: SEED_CREATOR_USER_ID,
        role: "creator",
        session_id: crypto.randomUUID(),
      },
      "wrong-secret-" + Math.random().toString(36).slice(2),
    );
    const r = await post({ listing_id: SEED_LISTING_ID }, `Bearer ${badJwt}`);
    expect(
      "wrong-secret JWT → 401 UNAUTHORIZED",
      r.status === 401 && r.data?.error === "UNAUTHORIZED",
      r,
    );
  }

  if (jwtSecret) {
    // 4. Lister-role JWT (valid signature, wrong role)
    {
      const listerJwt = await signMarketifyJwt(
        { sub: crypto.randomUUID(), role: "lister", session_id: crypto.randomUUID() },
        jwtSecret,
      );
      const r = await post({ listing_id: SEED_LISTING_ID }, `Bearer ${listerJwt}`);
      expect(
        "lister-role JWT → 403 FORBIDDEN",
        r.status === 403 && r.data?.error === "FORBIDDEN",
        r,
      );
    }

    const creatorJwt = await signMarketifyJwt(
      {
        sub: SEED_CREATOR_USER_ID,
        role: "creator",
        session_id: crypto.randomUUID(),
      },
      jwtSecret,
    );
    const creatorAuth = `Bearer ${creatorJwt}`;

    // 5. Malformed JSON body
    {
      const r = await post("{not-json", creatorAuth);
      expect(
        "malformed JSON → 400 INVALID_JSON",
        r.status === 400 && r.data?.error === "INVALID_JSON",
        r,
      );
    }

    // 6. Missing listing_id
    {
      const r = await post({}, creatorAuth);
      expect(
        "missing listing_id → 400 INVALID_REQUEST",
        r.status === 400 && r.data?.error === "INVALID_REQUEST",
        r,
      );
    }

    // 7. Non-UUID listing_id
    {
      const r = await post({ listing_id: "not-a-uuid" }, creatorAuth);
      expect(
        "non-UUID listing_id → 400 INVALID_REQUEST",
        r.status === 400 && r.data?.error === "INVALID_REQUEST",
        r,
      );
    }

    // 8. Unknown listing_id
    {
      const r = await post(
        { listing_id: "00000000-0000-0000-0000-000000000000" },
        creatorAuth,
      );
      expect(
        "unknown listing_id → 404 LISTING_NOT_FOUND",
        r.status === 404 && r.data?.error === "LISTING_NOT_FOUND",
        r,
      );
    }

    // 9. Happy path — seed creator is eligible for seed listing
    {
      const r = await post({ listing_id: SEED_LISTING_ID }, creatorAuth);
      const d = r.data;
      expect(
        "happy path → 200 with eligible:true + split conditions + sample_videos",
        r.status === 200 &&
          d?.listing?.id === SEED_LISTING_ID &&
          Array.isArray(d?.pre_conditions) &&
          d.pre_conditions.length >= 2 &&
          d.pre_conditions.every((c: { kind: string }) => c.kind === "pre") &&
          Array.isArray(d?.post_conditions) &&
          d.post_conditions.every((c: { kind: string }) => c.kind === "post") &&
          Array.isArray(d?.sample_videos) &&
          d.sample_videos.length >= 1 &&
          d?.eligibility?.eligible === true &&
          Array.isArray(d.eligibility.failed_conditions) &&
          d.eligibility.failed_conditions.length === 0 &&
          d.eligibility.has_active_application === false,
        r,
      );
    }

    if (serviceRoleKey) {
      // 10. Force-fail the TikTok min_followers pre-condition
      {
        await setCreatorMetric("tiktok_follower_count", 500);
        const r = await post({ listing_id: SEED_LISTING_ID }, creatorAuth);
        const d = r.data;
        const ttFail = (d?.eligibility?.failed_conditions ?? []).find(
          (f: { metric: string; platform: string }) =>
            f.metric === "min_followers" && f.platform === "tiktok",
        );
        expect(
          "below-threshold → 200 eligible:false + tiktok min_followers failure",
          r.status === 200 &&
            d?.eligibility?.eligible === false &&
            !!ttFail &&
            ttFail.required === 1000 &&
            ttFail.actual === 500,
          r,
        );
        // Restore immediately — the finally block also restores, but doing
        // it inline keeps state consistent if later assertions are added.
        await setCreatorMetric(
          "tiktok_follower_count",
          originalTiktokFollowerCount,
        );
      }
    }
  }

  console.log("all get-listing-detail smoke tests passed");
} finally {
  await restore();
}

// Edge function: get-listing-detail (US-039)
//
// Contract:
//   POST { listing_id: string }
//     → 200 {
//         listing:          <row from public.listings>,
//         pre_conditions:   <rows from listing_conditions where kind='pre'>,
//         post_conditions:  <rows from listing_conditions where kind='post'>,
//         sample_videos:    <rows from sample_videos>,
//         eligibility: {
//           eligible:                boolean,
//           failed_conditions:       Array<{metric, platform, required, actual}>,
//           has_active_application:  boolean,
//         }
//       }
//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
//     → 401 { error: 'UNAUTHORIZED' }
//     → 403 { error: 'FORBIDDEN' }       // non-creator role
//     → 404 { error: 'LISTING_NOT_FOUND' } // also covers draft listings for non-owners
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
//
// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
//       _shared/jwt.ts and asserts role='creator'. Deployed with
//       verify_jwt=false at the gateway because the gateway only knows
//       about Supabase's own JWT secret — the handler enforces auth.
//
// Response shape — primary reference is docs/tech-architecture.md §5.4
// (the spec's `failed_conditions: Array<{metric, required, actual}>` wins
// over the story's `reasons: string[]`; spec is authoritative per the
// Ralph iteration rules). `pre_conditions` / `post_conditions` are split
// at the edge per the story AC — the DB persists them in a single
// `listing_conditions` table discriminated by `kind`.
//
// Eligibility — only PRE conditions gate apply-time eligibility per
// docs/tech-architecture.md §6.3 ("Pre-conditions: evaluated on all
// posts; post-conditions: evaluated on submissions"). POST conditions
// are returned in the response for the UI to display but do not
// contribute to `eligible` / `failed_conditions`.
//
// Fail-closed on missing metrics (§3d): when the creator hasn't been
// scraped yet (or a specific platform field is NULL), the PRE condition
// keyed on that field fails — the spec calls this out explicitly for
// Instagram `min_avg_views_last_n` ("Listings that require … treat null
// as ineligible (fail-closed).") and we apply the same rule uniformly.

import { createClient } from "npm:@supabase/supabase-js@2";
import { verifyJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

type Platform = "tiktok" | "instagram";
type ConditionKind = "pre" | "post";

interface ConditionRow {
  id: string;
  listing_version_id: string;
  kind: ConditionKind;
  metric: string;
  platform: Platform | null;
  operator: string;
  numeric_threshold: string | number | null;
  text_threshold: string | null;
  bool_threshold: boolean | null;
  created_at: string;
}

interface CreatorProfileRow {
  tiktok_follower_count: number | null;
  tiktok_avg_views_last_10: number | null;
  tiktok_total_likes: number | null;
  tiktok_video_count: number | null;
  tiktok_is_verified: boolean | null;
  instagram_follower_count: number | null;
  instagram_avg_views_last_10: number | null;
  instagram_media_count: number | null;
}

interface FailedCondition {
  metric: string;
  platform: Platform | null;
  required: number | boolean;
  actual: number | boolean | null;
}

interface DetailRequest {
  listing_id?: unknown;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function bearerToken(req: Request): string | null {
  const raw = req.headers.get("Authorization") ??
    req.headers.get("authorization");
  if (!raw) return null;
  const m = raw.match(/^Bearer\s+(.+)$/i);
  return m ? m[1].trim() : null;
}

// Evaluate a single pre-condition against the creator's denormalized
// metrics. Returns `null` on pass, or the failed-condition detail on fail.
// Missing data (null actual for a numeric threshold) fails closed per §3d.
function evaluatePreCondition(
  condition: ConditionRow,
  metrics: CreatorProfileRow,
): FailedCondition | null {
  const { metric, platform, operator } = condition;
  if (operator === "gte") {
    const required = Number(condition.numeric_threshold);
    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
    const actual = readNumericMetric(metrics, platform, metric);
    if (actual === null || actual < required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  if (operator === "bool") {
    const required = condition.bool_threshold === true;
    const actual = readBoolMetric(metrics, platform, metric);
    if (actual !== required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  // Other operators (eq/contains/lte/etc.) are reserved for post-conditions
  // (e.g. post_must_mention uses 'contains') — never reachable here because
  // this function is only called for kind='pre'. If a future migration adds
  // a pre-condition with an unknown operator, skip it rather than fail it.
  return null;
}

function readNumericMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): number | null {
  if (platform === "tiktok") {
    switch (metric) {
      case "min_followers":
        return metrics.tiktok_follower_count;
      case "min_avg_views_last_n":
        return metrics.tiktok_avg_views_last_10;
      case "min_total_likes":
        return metrics.tiktok_total_likes;
      case "min_videos_posted":
        return metrics.tiktok_video_count;
      default:
        return null;
    }
  }
  if (platform === "instagram") {
    switch (metric) {
      case "min_followers":
        return metrics.instagram_follower_count;
      case "min_avg_views_last_n":
        return metrics.instagram_avg_views_last_10;
      case "min_videos_posted":
        return metrics.instagram_media_count;
      default:
        return null;
    }
  }
  return null;
}

function readBoolMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): boolean | null {
  if (platform === "tiktok" && metric === "verified_only") {
    return metrics.tiktok_is_verified;
  }
  return null;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.role !== "creator") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let body: DetailRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const listingId =
    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
      ? body.listing_id
      : null;
  if (!listingId) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: listing, error: listingError } = await supabase
    .from("listings")
    .select("*")
    .eq("id", listingId)
    .maybeSingle();

  if (listingError) {
    console.error("listings lookup failed", listingError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  // Drafts are never visible to non-owners; any creator request for a
  // draft listing collapses to 404 so id existence doesn't leak across
  // listers.
  if (!listing || listing.status === "draft") {
    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
  }

  const versionId = listing.current_version_id as string | null;
  if (!versionId) {
    // Data-integrity guard — every non-draft listing should have a current
    // version by trigger (us_010). If one is missing, surface DB_ERROR
    // rather than returning an inconsistent response to the client.
    console.error("listing missing current_version_id", listing.id);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const [conditionsRes, videosRes, profileRes, appsRes] = await Promise.all([
    supabase
      .from("listing_conditions")
      .select("*")
      .eq("listing_version_id", versionId)
      .order("kind", { ascending: true })
      .order("metric", { ascending: true }),
    supabase
      .from("sample_videos")
      .select("*")
      .eq("listing_version_id", versionId)
      .order("sort_order", { ascending: true }),
    supabase
      .from("creator_profiles")
      .select(
        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
          "instagram_avg_views_last_10,instagram_media_count",
      )
      .eq("user_id", claims.sub)
      .maybeSingle(),
    supabase
      .from("applications")
      .select("id")
      .eq("listing_id", listingId)
      .eq("creator_id", claims.sub)
      .in("status", ["pending", "approved"])
      .limit(1),
  ]);

  if (conditionsRes.error) {
    console.error("listing_conditions lookup failed", conditionsRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (videosRes.error) {
    console.error("sample_videos lookup failed", videosRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (profileRes.error) {
    console.error("creator_profiles lookup failed", profileRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (appsRes.error) {
    console.error("applications lookup failed", appsRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
  const preConditions = conditions.filter((c) => c.kind === "pre");
  const postConditions = conditions.filter((c) => c.kind === "post");

  // Creator profile is created by the signup flow (US-014) so every
  // creator JWT should have one, but treat a missing row as fully-null
  // metrics — fail-closed on every numeric threshold.
  const metrics: CreatorProfileRow = profileRes.data ?? {
    tiktok_follower_count: null,
    tiktok_avg_views_last_10: null,
    tiktok_total_likes: null,
    tiktok_video_count: null,
    tiktok_is_verified: null,
    instagram_follower_count: null,
    instagram_avg_views_last_10: null,
    instagram_media_count: null,
  };

  const failed: FailedCondition[] = [];
  for (const c of preConditions) {
    const miss = evaluatePreCondition(c, metrics);
    if (miss) failed.push(miss);
  }
  const eligible = failed.length === 0;
  const hasActiveApplication = (appsRes.data ?? []).length > 0;

  return jsonResponse(200, {
    listing,
    pre_conditions: preConditions,
    post_conditions: postConditions,
    sample_videos: videosRes.data ?? [],
    eligibility: {
      eligible,
      failed_conditions: failed,
      has_active_application: hasActiveApplication,
    },
  });
});

