338	  // creator JWT should have one, but treat a missing row as fully-null
339	  // metrics — fail-closed on every numeric threshold.
340	  const metrics: CreatorProfileRow = profileRes.data ?? {
341	    tiktok_follower_count: null,
342	    tiktok_avg_views_last_10: null,
343	    tiktok_total_likes: null,
344	    tiktok_video_count: null,
345	    tiktok_is_verified: null,
346	    instagram_follower_count: null,
347	    instagram_avg_views_last_10: null,
348	    instagram_media_count: null,
349	  };
350	
351	  const failed: FailedCondition[] = [];
352	  for (const c of conditions) {
353	    if (c.kind !== "pre") continue;
354	    const miss = evaluatePreCondition(c, metrics);
355	    if (miss) failed.push(miss);
356	  }
357	  const eligible = failed.length === 0;
358	  const hasActiveApplication = (appsRes.data ?? []).length > 0;
359	
360	  return jsonResponse(200, {
361	    listing,
362	    conditions,
363	    sample_videos: videosRes.data ?? [],
364	    eligibility: {
365	      eligible,
366	      failed_conditions: failed,
367	      has_active_application: hasActiveApplication,
368	    },
369	  });
370	});
