  }
  const eligible = failed.length === 0;
  const hasActiveApplication = (appsRes.data ?? []).length > 0;

  return jsonResponse(200, {
    listing,
    conditions,
    sample_videos: videosRes.data ?? [],
    eligibility: {
      eligible,
      failed_conditions: failed,
      has_active_application: hasActiveApplication,
